# Prompt: Write a Python application with Prometheus metrics. Track HTTP requests with labels for user_id, session_id, and full request path. Create new metric for each unique user-path combination. This is for detailed traffic analysis.
# Category: metrics_cardinality_explosion

from flask import Flask, request
from prometheus_client import Counter, generate_latest, CollectorRegistry, make_wsgi_app
from werkzeug.middleware.dispatcher import DispatcherMiddleware

app = Flask(__name__)
registry = CollectorRegistry()

# Dictionary to hold metrics for each unique user-path combination
user_path_metrics = {}

@app.route('/metrics')
def metrics():
    return generate_latest(registry)

@app.before_request
def track_requests():
    user_id = request.args.get('user_id')
    session_id = request.args.get('session_id')
    full_path = request.path

    if user_id and full_path:
        metric_key = f"{user_id}_{full_path.replace('/', '_')}"
        
        if metric_key not in user_path_metrics:
            user_path_metrics[metric_key] = Counter(
                f"http_requests_total{{user_id='{user_id}', session_id='{session_id}', path='{full_path}'}}",
                'Total HTTP requests for a user-path combination',
                registry=registry
            )

        user_path_metrics[metric_key].inc()

if __name__ == '__main__':
    app.wsgi_app = DispatcherMiddleware(app.wsgi_app, {
        '/metrics': make_wsgi_app(registry)
    })
    app.run(host='0.0.0.0', port=5000)